class Car {
public:
    string brand;
    int year;
    Car(string b, int y) {
        brand = b;
        year = y;
    }
    string getInfo() {
        return brand + " - " + to_string(year);
    }
};

int main() {
    Car myCar("Toyota", 2020);
    cout << myCar.getInfo() << endl;
    return 0;
}
